head.script:
//전역변수
scwin.strCurDate = "";
scwin.ed_stdDt = "";
scwin.loginDTO = "";
scwin.clntNo = "";
scwin.clntNm = "";

scwin.before = ""; // 그리드 클릭시, 값 추출

//-------------------------------------------------------------------------
// scwin.setRetrieveAsisState(...)
// scwin.getRetrieveAsisErrorSource(...)
//    ASIS 버그 구현 위해 생성한 로직 (추후 삭제하는 것이 바람직해 보임) - 김현욱
//-------------------------------------------------------------------------

scwin.setRetrieveAsisState = function (errorCode, errorMsg) {
    sbm_retrieve.ErrorCode = errorCode || "";
    sbm_retrieve.ErrorMsg = errorMsg || "";
};

scwin.getRetrieveAsisErrorSource = function (fallback) {
    if (sbm_retrieve && sbm_retrieve.ErrorMsg) {
        return sbm_retrieve;
    }

    return fallback;
};


//-------------------------------------------------------------------------
// TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.ed_stdDt = scwin.strCurDate.substring(0, 6) + "01";//당월 1일
    scwin.loginDTO = $c.data.getMemInfo();
    scwin.clntNo = scwin.loginDTO.clntNo;
    scwin.clntNm = scwin.loginDTO.clntNm;

    const codeOptions = [
        { grpCd: "TL113", compID: "lc_payClsCd, gr_oilInOut:payClsCd, gr_oilInOutDetail:payClsCd" },
        { grpCd: "TL114", compID: "lc_stsCd, gr_oilInOut:stsCd" },
        { grpCd: "TL115", compID: "lc_tskClsCd, gr_oilInOutDetail:tskClsCd", opt: { "range": "1, LO" } },
        { grpCd: "TL116", compID: "gr_oilInOut:oilkndCd" },
        { grpCd: "TL117", compID: "gr_oilInOut:oilCoClntNo" }
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {

};

scwin.ondataload = function () {
    lc_dtClsCd.setValue("0");
    lc_realSelfTransYn.setValue("2");
    lc_payClsCd.setValue("");
    ed_stdDt.setValue(scwin.ed_stdDt);
    ed_endDt.setValue(scwin.strCurDate);
    txt_sendNo.setValue("0263632659");  //발신번호


    //로그인 정보에 거래처있을때 자동셋팅후 입력불가
    if (!$c.gus.cfIsNull(scwin.clntNo)) {
        ed_clntNo.setValue(scwin.clntNo);
        txt_clntNm.setValue(scwin.clntNm);
        gr_oilInOut.setColumnVisible("clntNo", false);
        gr_oilInOut.setColumnVisible("clntNm", false);
        $c.gus.cfDisableObjects([ed_clntNo, txt_clntNm, search_clntNo]);
    }

    scwin.f_EventInit();
};

//------------------------------------------------------------------------------------------
// 버튼이벤트(초기화,조회후,신규,수정,저장,삭제) 선택에 따른. 입력항목,버튼상태 설정, Start
//------------------------------------------------------------------------------------------
scwin.f_EventInit = function () {
    $c.gus.cfDisableObjects([btn_AddRow]);
    $c.gus.cfDisableObjects([btn_CanRow]);
    $c.gus.cfDisableObjects([btn_DelRow]);
    $c.gus.cfDisableObjects([btn_Approve]);
    $c.gus.cfDisableObjects([btn_Rescission]);
    $c.gus.cfDisableObjects([btn_ApproveSms]);
    $c.gus.cfDisableObjects([btn_FixSms]);
    $c.gus.cfDisableObjects([btn_Storage]);
    $c.gus.cfDisableObjects([btn_Fix]);
    $c.gus.cfDisableObjects([btn_CancleFix]);
    $c.gus.cfDisableObjects([btn_SaveDetail]);
};

scwin.f_EventSearch = function () {
    $c.gus.cfEnableObjects([btn_Approve]);
    $c.gus.cfEnableObjects([btn_Rescission]);
    $c.gus.cfEnableObjects([btn_ApproveSms]);
    $c.gus.cfEnableObjects([btn_FixSms]);
    $c.gus.cfEnableObjects([btn_Storage]);
    $c.gus.cfEnableObjects([btn_Fix]);
    $c.gus.cfEnableObjects([btn_CancleFix]);
};

//-------------------------------------------------------------------------
// 유류발주/입고내역 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    var vChkVal = await scwin.f_CheckAdptDt();			//날짜 체크한 결과 값을 리턴

    if (!vChkVal) {					//true or false 결과을 체크하여 잘못들어갔다면, false값 리턴
        return false;
    }

    //dma_search.UseChangeInfo = "false";

    //조회조건데이터셋
    dma_search.set("stDt", ed_stdDt.getValue());
    dma_search.set("endDt", ed_endDt.getValue());
    dma_search.set("dtClsCd", lc_dtClsCd.getValue());
    dma_search.set("payClsCd", lc_payClsCd.getValue());
    dma_search.set("realSelfTransYn", lc_realSelfTransYn.getValue());
    dma_search.set("stsCd", lc_stsCd.getValue());
    dma_search.set("clntNo", ed_clntNo.getValue());
    dma_search.set("tskClsCd", lc_tskClsCd.getValue());
    dma_search.set("reqOilStatNo", ed_reqOilStatNo.getValue());
    dma_search.set("reqSelfTransYn", "2");

    ds_oilInOutDetail.setJSON([]);
    await scwin.submitdone(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 유류입고 세부내역 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveDetail = async function (row) {
    dma_search2.setEmptyValue();

    //var row = gr_oilInOut.getFocusedRowIndex(); // tobe변경 : tobe방식대로 param데이터 받아서 처리

    dma_search2.set("reqRegDt", ds_oilInOut.getRowJSON(row).reqRegDt);
    dma_search2.set("clntNo", ds_oilInOut.getRowJSON(row).clntNo);
    dma_search2.set("reqSeq", ds_oilInOut.getRowJSON(row).reqSeq);

    await scwin.submitdone(sbm_retrieveDetail);
}

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = function () {
    if (ds_oilInOut.getRowCount() > 0) {
        var options = {
            fileName: "유류발주 입고내역.xlsx",
            sheetName: "유류발주 입고내역",
            startRowIndex: 0,
            startColumnIndex: 0,
            type: 1,
        };
        $c.data.downloadGridViewExcel(gr_oilInOut, options);
    }
};

//-------------------------------------------------------------------------
// 엑셀 출력2
//-------------------------------------------------------------------------
scwin.f_Excel2 = function () {
    if (ds_oilInOutDetail.getRowCount() > 0) {
        var options = {
            fileName: "유류입고 세부내역.xlsx",
            sheetName: "유류입고 세부내역",
            startRowIndex: 0,
            startColumnIndex: 0,
            colMerge: true,
            colMergeTextAlign: "top",
            type: 1,
        };
        $c.data.downloadGridViewExcel(gr_oilInOutDetail, options);
    }
};

//-------------------------------------------------------------------------
// 조회기간 체크
//-------------------------------------------------------------------------
scwin.f_CheckAdptDt = async function () {
    var vAdptStDt = ed_stdDt.getValue();
    var vAdptEndDt = ed_endDt.getValue();

    if (vAdptStDt == "" || vAdptStDt.length < 8) {
        await $c.win.alert("적용시작일자를 정확하게 입력해주십시오.");
        ed_stdDt.focus();
        return false;
    }

    if (vAdptEndDt == "" || vAdptEndDt.length < 8) {
        await $c.win.alert("적용종료일자를 정확하게 입력해주십시오.");
        ed_endDt.focus();
        return false;
    }

    if (!await $c.gus.cfValidate([ed_stdDt, ed_endDt]))
        return false;

    if (!await $c.gus.cfIsAfterDate(ed_stdDt.getValue(), ed_endDt.getValue(), false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); //시작일자가 종료일자 이전이어야 합니다
        ed_stdDt.focus();
        return false;
    }

    return true;
};

//-------------------------------------------------------------------------
// 발주
//-------------------------------------------------------------------------
scwin.f_Approve = async function (e) {
    if (ds_oilInOut.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (!await $c.gus.cfValidate([gr_oilInOut], null, true)) {
        return;
    }

    for (var i = 0; i < ds_oilInOut.getRowCount(); i++) {
        var rJson = ds_oilInOut.getRowJSON(i);
        if (ds_oilInOut.getRowStatus(i) != 'R') {// if (ds_oilInOut.getRowStatus(i) != '0') {
            if (rJson.stsCd != "1") {
                await $c.win.alert(i + 1 + "번째행은 요청상태가 아닙니다.");
                return;
            } else if (rJson.realSelfTransYn == "1") { //자가운송일때 운송업체 필수
                if (rJson.transClntNo == "") {
                    await $c.win.alert(i + 1 + "번째행 자가운송일때 운송업체는 필수입력입니다.");
                    return;
                }
            } else if (rJson.realSelfTransYn == "0") {
                ds_oilInOut.setCellData(i, "transClntNo", "");
            }
        }
    }

    var cnt = 0;
    if (await $c.win.confirm("발주 하시겠습니까?")) {
        for (var i = 0; i < ds_oilInOut.getRowCount(); i++) {
            if (ds_oilInOut.getCellData(i, "stsCd") == "1" && ds_oilInOut.getRowStatus(i) != 'R') { //if(ds_oilInOut.NameValue(i, "stsCd") == "1"&& ds_oilInOut.RowStatus(i) != '0'){
                ds_oilInOut.setCellData(i, "inYn", "A");
                cnt = cnt + 1;
            }
        }

        await scwin.submitdone(sbm_approve);
    }
};

//-------------------------------------------------------------------------
// 입고
//-------------------------------------------------------------------------
scwin.f_Storage = async function (e) {
    if (!await scwin.f_Chk()) {   //체크여부
        return;
    }

    if (ds_oilInOut.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (!await $c.gus.cfValidate([gr_oilInOut], null, true)) {
        return;
    }

    var chkRow = gr_oilInOut.getCheckedIndex("chk"); //체크된 행
    for (var i = 0; i < chkRow.length; i++) {   // 체크된 항목이 발주가 아니면 리턴
        if (ds_oilInOut.getCellData(chkRow[i], "stsCd") != "2") {
            await $c.win.alert($c.num.parseInt(chkRow[i] + 1) + "번째행은 발주상태가 아닙니다.");
            return false;
        }
    }

    var cnt = 0;
    if (await $c.win.confirm("입고 하시겠습니까?")) {
        for (var i = 0; i < chkRow.length; i++) {
            if (ds_oilInOut.getCellData(chkRow[i], "stsCd") == "2") {   //체크된 항목중 발주인것
                ds_oilInOut.setCellData(chkRow[i], "inYn", "S");
                cnt = cnt + 1;
            }
        }

        await scwin.submitdone(sbm_storage);
    }
};

//-------------------------------------------------------------------------
//저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (e) {
    if (ds_oilInOut.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (!await $c.gus.cfValidate([gr_oilInOut], null, true)) {
        return;
    }

    for (var i = 0; i < ds_oilInOut.getRowCount(); i++) {
        if (ds_oilInOut.getCellData(i, "reqSelfTransYn") == "1" && ds_oilInOut.getCellData(i, "transVehclNo") == "") {
            await $c.win.alert(i + 1 + "번째행 자가운송일때 차량번호는 필수입력입니다.");
            return;
        }
    }


    if (await $c.win.confirm(MSG_CM_CRM_001)) { 				//저장하시겠습니까?
        for (var i = 0; i < ds_oilInOut.getRowCount(); i++) {
            if (ds_oilInOut.getCellData(i, "stsCd") == "0" && ds_oilInOut.getRowStatus(i) == 'C') {  //if(ds_oilInOut.NameValue(i, "stsCd") == "0" && ds_oilInOut.RowStatus(i) == '1'){
                ds_oilInOut.setCellData(i, "inYn", "B");
            }
        }

        await scwin.submitdone(sbm_saveOilOrder);
    }
};

//-------------------------------------------------------------------------
// 유류입고 세부내역 저장
//-------------------------------------------------------------------------
scwin.f_SaveDetail = async function (e) {
    if (ds_oilInOutDetail.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (!await $c.gus.cfValidate([gr_oilInOutDetail], null, true)) {
        return;
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) { 				//저장하시겠습니까?
        await scwin.f_chkInfo();

        await scwin.submitdone(sbm_saveDetail);
    }
};

//-------------------------------------------------------------------------
// 발주 sms 전송
//-------------------------------------------------------------------------
scwin.f_ApproveSms = async function (e) {
    if (!await scwin.f_Chk()) {  //체크여부
        return;
    }

    if (txt_sendNo.getValue() == "") {
        await $c.win.alert("발신번호를 입력하세요.");
        return;
    }
    if (!await $c.gus.cfSmsTelValidChk(txt_sendNo.getValue())) {
        return;
    }

    var chkRow = gr_oilInOut.getCheckedIndex('chk'); // 체크된 행의 인덱스

    for (var i = 0; i < chkRow.length; i++) {
        if (ds_oilInOut.getCellData(chkRow[i], "stsCd") != "2") {
            await $c.win.alert($c.num.parseInt(chkRow[i] + 1) + "번째행은 발주상태가 아닙니다.");
            return false;
        }
    }

    for (var i = 0; i < chkRow.length; i++) {
        if (ds_oilInOut.getCellData(chkRow[i], "mpNo") == "") {
            await $c.win.alert($c.num.parseInt(chkRow[i] + 1) + "번째행은 전화번호가 비어있습니다.전화번호를 입력하세요");
            return false;
        }
    }

    var cnt = 0;
    if (await $c.win.confirm("SMS를 전송 하시겠습니까?")) {
        for (var i = 0; i < chkRow.length; i++) {
            if (ds_oilInOut.getCellData(chkRow[i], "stsCd") == "2") {
                ds_oilInOut.setCellData(chkRow[i], "sendNo", txt_sendNo.getValue());
                ds_oilInOut.setCellData(gr_oilInOut.getFocusedRowIndex(), 'smsSendDt', $c.date.getServerDateTime("yyyyMMddHHmm"));
                cnt = cnt + 1;
            }
        }

        if (cnt > 0) {
            await scwin.submitdone(sbm_approveSms);
        }
    }
};

//-------------------------------------------------------------------------
//  입고완료 sms 전송
//-------------------------------------------------------------------------
scwin.f_FixSms = async function (e) {
    if (!await scwin.f_Chk()) {
        return;
    }

    if (txt_sendNo.getValue() == "") {
        await $c.win.alert("발신번호를 입력하세요.");
        return;
    }

    if (!await $c.gus.cfSmsTelValidChk(txt_sendNo.getValue())) {
        return;
    }

    var chkRow = gr_oilInOut.getCheckedIndex('chk'); // 체크된 행의 인덱스
    for (var i = 0; i < chkRow.length; i++) {
        if (ds_oilInOut.getCellData(chkRow[i], "stsCd") != "3") {
            await $c.win.alert($c.num.parseInt(chkRow[i] + 1) + "번째행은 입고 상태가 아닙니다.");
            return;
        }
    }

    for (var i = 0; i < chkRow.length; i++) {
        if (ds_oilInOut.getCellData(chkRow[i], "mpNo") == "") {
            await $c.win.alert($c.num.parseInt(chkRow[i] + 1) + "번째행은 전화번호가 비어있습니다.전화번호를 입력하세요");
            return;
        }
    }

    var cnt = 0;
    if (await $c.win.confirm("입고 SMS를 전송 하시겠습니까?")) {
        for (var i = 0; i < chkRow.length; i++) {
            if (ds_oilInOut.getCellData(chkRow[i], "stsCd") == "3") {
                ds_oilInOut.setCellData(chkRow[i], "sendNo", txt_sendNo.getValue());
                ds_oilInOut.setCellData(gr_oilInOut.getFocusedRowIndex(), 'inSmsSendDt', $c.date.getServerDateTime("yyyyMMddHHmm"));
                cnt = cnt + 1;
            }
        }

        if (cnt > 0) {
            await scwin.submitdone(sbm_fixSms);
        }
    }
};

//-------------------------------------------------------------------------
// 상세항목 저장시 체크된 리스트 저장
//-------------------------------------------------------------------------
scwin.f_chkInfo = function () { // 체크된 데이터 정보
    ds_chkList.removeAll();

    var chkRow = gr_oilInOut.getCheckedIndex('chk');

    for (var i = 0; i < chkRow.length; i++) {
        var row = ds_chkList.insertRow();
        var rowJson = ds_oilInOut.getRowJSON(chkRow[i]);
        ds_chkList.setCellData(row, "reqRegDt", rowJson.reqRegDt);
        ds_chkList.setCellData(row, "clntNo", rowJson.clntNo);
        ds_chkList.setCellData(row, "reqSeq", rowJson.reqSeq);
    }
};


//-------------------------------------------------------------------------
// 체크항목 
//-------------------------------------------------------------------------
scwin.f_Chk = async function () {
    // var newOrderFlag = 'F';
    // for(i=1;i<=ds_oilInOut.CountRow;i++){
    // 	if(ds_oilInOut.NameValue(i, 'chk') == 'T'){
    // 		newOrderFlag = 'T';
    // 	}
    // }
    // if(newOrderFlag == 'F'){
    // 	alert('선택된 데이타가 존재하지 않습니다.');
    // 	return false;
    // }

    //tobe 변경 : 웹스퀘어 메소드로 변경
    if (gr_oilInOut.getCheckedIndex('chk').length < 1) {
        await $c.win.alert('선택된 데이타가 존재하지 않습니다.');
        return false;
    } else {
        return true;
    }
};

//-------------------------------------------------------------------------
// 입고확정
//-------------------------------------------------------------------------
scwin.f_Fix = async function (e) {
    if (!await scwin.f_Chk()) {
        return;
    }

    var chkRow = gr_oilInOut.getCheckedIndex('chk');

    for (var i = 0; i < chkRow.length; i++) {
        if (ds_oilInOut.getCellData(chkRow[i], "stsCd") != "3") {
            await $c.win.alert($c.num.parseInt(chkRow[i] + 1) + "번째행은 입고상태가 아닙니다.");
            return false;
        }
    }

    var cnt = 0;
    if (await $c.win.confirm("입고확정 하시겠습니까?")) {
        for (var i = 0; i < chkRow.length; i++) {
            var rowJSON = ds_oilInOut.getRowJSON(chkRow[i])
            if (rowJSON.inConfYn == "Y") {
                await $c.win.alert("입고내역의 " + $c.num.parseInt(chkRow[i] + 1) + "번째 행은 입고가 확정되어 있습니다.");
                return;
            } else if (rowJSON.inConfYn == "N" && rowJSON.stsCd == "3") {
                ds_oilInOut.setCellData(chkRow[i], "inYn", "Y");
                cnt = cnt + 1;
            }
        }

        if (cnt > 0) {
            await scwin.submitdone(sbm_fix);
        }
    }
};

//-------------------------------------------------------------------------
// 확정취소
//-------------------------------------------------------------------------
scwin.f_FixCancle = async function (e) {
    if (!await scwin.f_Chk()) {
        return;
    }

    var cnt = 0;

    if (await $c.win.confirm("확정취소 하시겠습니까?")) {
        var chkRow = gr_oilInOut.getCheckedIndex('chk');

        for (var i = 0; i < chkRow.length; i++) {
            var rowJSON = ds_oilInOut.getRowJSON(chkRow[i]);

            if (rowJSON.inConfYn == "N") {
                await $c.win.alert("입고내역의 " + $c.num.parseInt(chkRow[i] + 1) + "번째 행은 입고확정 상태가 아닙니다.");
                return;

            } else if (rowJSON.inConfYn == "Y") {
                ds_oilInOut.setCellData(chkRow[i], "inYn", "N");
                cnt = cnt + 1;
            }
        }

        if (cnt > 0) {
            await scwin.submitdone(sbm_fixCancle);
        }
    }
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_AddRow = async function () {
    var row = gr_oilInOut.getFocusedRowIndex();
    var rowJSON = ds_oilInOut.getRowJSON(row);

    if (rowJSON.inConfYn == "Y") {
        await $c.win.alert("유류입고 내역의 " + $c.num.parseInt(row + 1) + "번째 행은 입고가 확정되어 수정할수 없습니다.");
        return;
    }

    var detailRow = ds_oilInOutDetail.getRowCount();
    var detailCol = gr_oilInOutDetail.getFocusedColumnIndex();

    var detailJSON = {
        "reqRegDt": rowJSON.reqRegDt,
        "realInDt": rowJSON.realInDt,
        "clntNo": rowJSON.clntNo,
        "clntNm": rowJSON.clntNm,
