scwin.f_AddRowMaster = function () {
    var row = ds_oilInOut.getRowCount();
    var col = gr_oilInOut.getFocusedColumnIndex() || 0;

    var rowJSON = {
        'reqRegDt': $c.date.getServerDateTime("yyyyMMdd"),
        'reqInDt': $c.date.getServerDateTime("yyyyMMdd"),
        'stsCd': "0",
        'reqSelfTransYn': "0",
        'clntNo': ed_clntNo.getValue(),
        'clntNm': txt_clntNm.getValue(),
        'reqOilStatNo': ed_reqOilStatNo.getValue(),
        'reqOilStatNm': txt_reqOilStatNm.getValue()
    };

    ds_oilInOut.setRowJSON(row, rowJSON);

    if (ed_reqOilStatNo.getValue() != "") {
        //var clntNo = ds_oilInOut.getRowJSON(row).clntNo;
        clntNo = "";

        udc_comCode.setSelectId('retrieveOilStatClntNo');
        udc_comCode.cfCommonPopUpAsync(
            function (rtnList) {
                if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
                    ds_oilInOut.setCellData(row, "reqOilStatNo", rtnList[0]);
                    ds_oilInOut.setCellData(row, "reqOilStatNm", rtnList[1]);
                    ds_oilInOut.setCellData(row, "mpNo", rtnList[2]);
                    ds_oilInOut.setCellData(row, "reqNm", rtnList[3]);
                    //294371 (주)삼양주유소(보관) -> 최은광 01034449364, 262126 (주)동부메탈(생산물류) -> 오명근 01066696058 //2021.12.29 장원석주임 요청
                    if ("294371" == rtnList[0]) {
                        ds_oilInOut.setCellData(row, "mpNo", "01034449364");
                        ds_oilInOut.setCellData(row, "reqNm", "최은광");

                    } else if ("262126" == rtnList[0]) {
                        ds_oilInOut.setCellData(row, "mpNo", "01066696058");
                        ds_oilInOut.setCellData(row, "reqNm", "오명근");
                    }
                }
            },
            ed_reqOilStatNo.getValue(),
            "",
            'T',
            null,
            null,
            null,
            null,
            clntNo,
            null,
            null,
            null,
            null
        ); // 거래처
    }

    if (!$c.gus.cfIsNull(scwin.clntNo)) {
        ds_oilInOut.setCellData(row, 'clntNo', scwin.clntNo);
        ds_oilInOut.setCellData(row, 'clntNm', scwin.clntNm);
        gr_oilInOut.setColumnReadOnly("clntNo", true);
        gr_oilInOut.setColumnReadOnly("clntNm", true);
    }

    gr_oilInOut.setFocusedCell(row, col);
};

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Rescission = async function (e) {
    if (!await scwin.f_Chk()) {
        return;
    }

    var chkRow = gr_oilInOut.getCheckedIndex('chk');

    for (var i = 0; i < chkRow.length; i++) {
        if (ds_oilInOut.getCellData(chkRow[i], "stsCd") == "0" || ds_oilInOut.getCellData(chkRow[i], "stsCd") == "1") {
            await $c.win.alert($c.num.parseInt(chkRow[i] + 1) + "번째행은 입고 또는 발주상태가 아닙니다.");
            return;
        }
    }

    var cnt = 0;
    if (await $c.win.confirm("취소하시겠습니까?(입고일때  발주, 발주일때 요청 상태로 변경됩니다)")) {
        for (var i = 0; i < chkRow.length; i++) {
            if (ds_oilInOut.getCellData(chkRow[i], "inConfYn") == "Y") {
                await $c.win.alert("입고내역의 " + $c.num.parseInt(chkRow[i] + 1) + "번째 행은 입고가 확정되어 삭제할수 없습니다.");
                return;

            } else if (ds_oilInOut.getCellData(chkRow[i], "inConfYn") == "N") {
                ds_oilInOut.setCellData(chkRow[i], "inYn", "R");
                cnt = cnt + 1;
            }
        }
        if (cnt > 0) {
            await scwin.submitdone(sbm_rescission);
        }
    }
};

//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_DelRow = async function () {
    if (ds_oilInOutDetail.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
        return;
    }

    var row = gr_oilInOutDetail.getFocusedRowIndex();

    if (ds_oilInOutDetail.getCellData(row, "inConfYn") == "Y") {
        await $c.gus.alert("유류입고 세부내역의 " + $c.num.parseInt(row + 1) + "번째 행은 입고가 확정되어 삭제할수 없습니다.");
        return;
    }

    if (ds_oilInOutDetail.getRowStatus(row) == "C") {
        ds_oilInOutDetail.removeRow(row);
    } else {
        ds_oilInOutDetail.deleteRow(row);
    }
};

