//서비스 후처리
scwin.submitdone = async function (sbm) {
    var e = null;

    try {
        e = await $c.sbm.execute(sbm);
    } catch (ex) {
        switch (sbm) {
            case sbm_approveSms:
            case sbm_fixSms:
                await $c.gus.cfShowError(scwin.getRetrieveAsisErrorSource(ex));
                return false;
            default:
                throw ex;
        }
    }

    if (e.responseJSON.resultDataSet[0].Msg == 'FAIL') { //실패시
        switch (sbm) {
            case sbm_approveSms:
            case sbm_fixSms:
                await $c.gus.cfShowError($p, scwin.getRetrieveAsisErrorSource(e));
                break;
            default:
                break;
        }
        return false;
    }

    //성공시
    switch (sbm) {
        case sbm_approve: //발주
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.f_Retrieve();
            break;
        case sbm_saveOilOrder: //저장
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.f_Retrieve()
            break;
        case sbm_rescission: //발주
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.f_Retrieve();
            break;
        case sbm_saveDetail: //detail 저장
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            await scwin.f_Retrieve();

            for (i = 0; i < ds_oilInOut.getRowCount(); i++) { // 재 조회시 체크항목 유지
                var oilInOutJSON = ds_oilInOut.getRowJSON(i);
                for (j = 0; j < ds_chkList.getRowCount(); j++) {
                    var chkListRowJSON = ds_chkList.getRowJSON(j);
                    if (chkListRowJSON.reqRegDt == oilInOutJSON.reqRegDt &&
                        chkListRowJSON.clntNo == oilInOutJSON.clntNo &&
                        chkListRowJSON.reqSeq == oilInOutJSON.reqSeq) {
                        gr_oilInOut.setCellChecked(i, "chk", true);
                    }
                }
            }
            break;
        case sbm_storage: //입고
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.f_Retrieve();
            break;
        case sbm_retrieve: //조회
            //for=ds_oilInOut	event=OnLoadCompleted(rowCnt)
            scwin.setRetrieveAsisState("TRAN-50000", "[TRAN-50000] 성공하였습니다.");
            var rowCnt = ds_oilInOut.getRowCount();
            totalRows1.setValue(rowCnt);

            if (rowCnt == 0) {
                //ds_oilInOutDetail.setJSON([]); //tobe 위치 변경 : beforeRowPosition 문제로 조회전에 미리 초기화 시켜줌 
                totalRows2.setValue(rowCnt);
                await scwin.f_EventInit();
                await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            } else {
                scwin.f_EventSearch();

                gr_oilInOut.setFocusedCell(0, 0);
            }
            break;
        case sbm_retrieveDetail: // Detail조회
            //for=ds_oilInOutDetail	event=OnLoadCompleted(rowCnt)
            var rowCnt = ds_oilInOutDetail.getRowCount();
            totalRows2.setValue(rowCnt);

            if (rowCnt > 0) {
                gr_oilInOutDetail.setFocusedCell(0, 0);
            }
            break;
        case sbm_approveSms: //발주 sms전송
            await $c.win.alert("발주 SMS전송이 완료되었습니다.");
            scwin.f_Retrieve();
            break;
        case sbm_fixSms: //입고 sms전송
            await $c.win.alert("입고 SMS전송이 완료되었습니다.");
            scwin.f_Retrieve();
            break;
        case sbm_fix: //입고확정
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.f_Retrieve();
            break;
        case sbm_fixCancle: //확정취소
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.f_Retrieve();
            break;
        default:
            break;
    }
};

