scwin.gr_oilInOutDetail_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    var detailRowInConfYn = ds_oilInOutDetail.getRowJSON(rowIndex).inConfYn
    //입고확정시 수정불가
    if (detailRowInConfYn == "Y") {
        gr_oilInOutDetail.setColumnReadOnly("tskClsCd", true);
        gr_oilInOutDetail.setColumnReadOnly("oilStatClntNo", true);
        gr_oilInOutDetail.setColumnReadOnly("inQty", true);
        gr_oilInOutDetail.setColumnReadOnly("inDt", true);

    } else if (detailRowInConfYn == "N") {
        gr_oilInOutDetail.setColumnReadOnly("tskClsCd", false);
        gr_oilInOutDetail.setColumnReadOnly("oilStatClntNo", false);
        gr_oilInOutDetail.setColumnReadOnly("inQty", false);
        gr_oilInOutDetail.setColumnReadOnly("inDt", false);
    }
};

//tobe추가 : asis 그리드 컬럼 처음에 빈값일시, 팝업호출 안되서 추가.
scwin.gr_oilInOut_onbeforeedit = function (rowIndex, columnIndex, value) {
    var colid = gr_oilInOut.getColumnID(columnIndex);
    if (colid == "clntNo" || colid == "reqOilStatNm" || colid == "transClntNo") {
        scwin.before = value
    }
};

//for=gr_oilInOut event=OnExit(row,colid)
scwin.gr_oilInOut_onafteredit = function (rowIndex, columnIndex, value) {
    if (document.activeElement.getAttribute('data-inputtype') == 'textImage') return;

    //tobe추가 : asis 첫값이 빈값일시, 팝업창 안띄움.
    if (scwin.before == value) return;
    scwin.before = "";

    if (rowIndex >= 0) {
        var colid = gr_oilInOut.getColumnID(columnIndex);
        scwin.f_openPopUp(rowIndex, colid);
    }
};

//for=gr_oilInOutDetail event=OnExit(row,colid)
scwin.gr_oilInOutDetail_onafteredit = function (rowIndex, columnIndex, value) {
    if (document.activeElement.getAttribute('data-inputtype') == 'textImage') return;

    if (rowIndex >= 0) {
        var colid = gr_oilInOutDetail.getColumnID(columnIndex);

        //tobe추가 : 정소희 책임님 개선사항으로 추가. 빈값일시, 팝업창 안띄움.
        if (colid == "oilStatClntNo") {
            if (ds_oilInOutDetail.getCellData(rowIndex, colid) == "") {
                ds_oilInOutDetail.setCellData(rowIndex, "oilStatClntNm", "")
            }else{
                scwin.f_openPopUp(rowIndex, colid);
            }
        }
    }
};

//for=ed_clntNo event=onKillFocus()
scwin.udc_clnt_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, txt_clntNm, 1);
};

//tobe추가 : 정소희 책임님 개선요청으로 추가.
scwin.udc_reqOilStat_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_reqOilStatNo, txt_reqOilStatNm, 2);
};

//for=ds_oilInOut event=CanRowPosChange(row) 
scwin.ds_oilInOut_onbeforerowpositionchange = function (info) {
    if ($c.gus.cfIsNull(info.newRowIndex) || ds_oilInOutDetail.getRowCount() == 0) return;

    if (ds_oilInOutDetail.getModifiedIndex().length > 0) {
        $c.gus.cfAlertMsg("유류입고 세부내역이 수정중입니다. 수정을 완료하세요");
        return false;
    }

    scwin.click = false;
};

scwin.inConfYn_customFormatter = function (data) {
    var result = "";

    if (data == "Y") {
        result = "확정";
    } else {
        result = "미확정";
    }

    return result;
}

// 수량 컬럼 빈값일시, 0 셋팅
scwin.zeroEmpty = function (data, formattedData, rowIndex, colIndex) {
    if (data == "") {
        return 0
    }
    return formattedData
};
